   | "square"
   | "triangle"
   | "diamond"
   | "hexagon"
   | "rectangle"
   | "star";

 interface ThemeToggleProps extends React.ComponentPropsWithoutRef<"button"> {
   duration?: number;
   variant?: TransitionVariant;
   /** When true, the transition expands from the viewport center instead of the button center. */
   fromCenter?: boolean;
