         point(cx, cy - R),
         point(cx + R, cy),
         point(cx, cy + R),
         point(cx - R, cy),
       ].join(", ");
       return [polygonCollapsed(point(cx, cy), 4), `polygon(${end})`];
     }
     case "hexagon": {
       const R = maxRadius * Math.SQRT2;
