display.text:
"use client";

import {
  DialRoot,
  SelectControl,
  Slider,
  Toggle,
  useDialKitController,
} from "dialkit";

import { ThemeToggle } from "@/registry/new-york/theme-toggle";

const config = {
  duration: [100, 2000, 400] as [number, number, number],
  fromCenter: false,
  variant: {
    default: "circle",
    options: [
      "circle",
      "square",
      "triangle",
      "diamond",
      "hexagon",
      "rectangle",
      "star",
    ],
    type: "select",
  },
};

export const ThemeToggleDemo = () => {
  const { values, setValue } = useDialKitController("theme-toggle", config);

  return (
    <DialRoot>
      <div className="flex flex-col items-center gap-8">
        <ThemeToggle
          variant={values.variant as any}
          fromCenter={values.fromCenter}
          duration={values.duration}
          className="inline-flex h-10 w-10 items-center justify-center rounded-full border border-border bg-card text-foreground"
        />
        <div className="flex flex-col gap-3 w-full max-w-xs">
          <SelectControl
            label="Variant"
            value={values.variant as string}
            options={config.variant.options}
            onChange={(v) => setValue("variant", v)}
          />
          <Toggle
            label="From center"
            checked={values.fromCenter}
            onChange={(v) => setValue("fromCenter", v)}
          />
          <Slider
            label="Duration"
            value={values.duration}
            min={100}
            max={2000}
            step={50}
            unit="ms"
            onChange={(v) => setValue("duration", v)}
          />
        </div>
      </div>
    </DialRoot>
  );
};

